          petal.style.animationDelay = delay + 's';

          contentBox.appendChild(petal);

          (function(el, parent, t) {
            setTimeout(function() {
              if (el.parentNode === parent) parent.removeChild(el);
            }, t);
          })(petal, contentBox, (duration + delay) * 1000);
        }
      }

